A user clicks a "Delete" button on a task in a todo app. Given this code, what is the correct order of events?

```tsx
// TaskItem.tsx
const TaskItem = ({ task, onDelete }: TaskItemProps) => (
  <li>
    {task.title}
    <button onClick={() => onDelete(task.id)}>Delete</button>
  </li>
);

// TaskList.tsx (parent)
import { useTasks } from "../hooks/useTasks";

const TaskList = () => {
  const { tasks, removeTask } = useTasks();
  return (
    <ul>
      {tasks.map(task => (
        <TaskItem key={task.id} task={task} onDelete={removeTask} />
      ))}
    </ul>
  );
};
```

