You see this code and a bug report: "The search results do not update when I switch from the Products page to the Users page." What is the likely cause?

```tsx
// src/hooks/useSearch.ts
export const useSearch = (endpoint: string) => {
  const [query, setQuery] = useState("");
  const [results, setResults] = useState([]);

  useEffect(() => {
    if (query) {
      fetch(`${endpoint}?q=${query}`)
        .then(res => res.json())
        .then(data => setResults(data));
    }
  }, [query]);

  return { query, setQuery, results };
};

// Used in pages:
const { query, setQuery, results } = useSearch("/api/products");
const { query, setQuery, results } = useSearch("/api/users");
```
